import React, { useState, useEffect, useCallback } from 'react';
import { filterEvents, getAllEvents } from '../../api/api';
import EventCard from '../../components/user/EventCard';
import toast from 'react-hot-toast';

const TYPES    = ['ALL','MOVIE','CONCERT','EVENT'];
const GENRES   = ['ALL','Action','Drama','Comedy','Romance','Horror','Thriller','Pop','Rock','Classical','Festival','Sports','Cultural'];
const LANGS    = ['ALL','English','Tamil','Hindi','Telugu','Malayalam','Kannada'];
const STATUSES = ['ALL','ACTIVE','COMPLETED','CANCELLED'];
const SORT_OPTIONS = [
  { value: '',      label: 'Default'   },
  { value: 'name',  label: 'Name A→Z'  },
  { value: 'type',  label: 'Type'      },
  { value: 'genre', label: 'Genre'     },
];

const BrowsePage = () => {
  const [events, setEvents]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({ type: '', genre: '', language: '', status: 'ACTIVE' });
  const [sortBy, setSortBy]   = useState('');
  const [search, setSearch]   = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    try {
      // build params — omit empty values
      const params = {};
      if (filters.type)     params.type     = filters.type;
      if (filters.genre)    params.genre    = filters.genre;
      if (filters.language) params.language = filters.language;
      if (filters.status)   params.status   = filters.status;
      if (search)           params.name     = search;

      const res  = await filterEvents(params);
      let data   = Array.isArray(res.data?.data) ? res.data.data : [];

      // apply client-side sort if selected
      if (sortBy) {
        const res2   = await getAllEvents(sortBy);
        const sorted = Array.isArray(res2.data?.data) ? res2.data.data : [];
        const ids    = new Set(data.map((e) => e.eventId));
        data = sorted.filter((e) => ids.has(e.eventId));
      }

      setEvents(data);
    } catch { toast.error('Failed to load events'); }
    finally { setLoading(false); }
  }, [filters, sortBy, search]);

  useEffect(() => { load(); }, [load]);

  const setFilter = (key, val) => setFilters((f) => ({ ...f, [key]: val === 'ALL' ? '' : val }));

  return (
    <div style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      {/* Hero */}
      <div style={{ background: 'linear-gradient(135deg,#fff8f5 0%,#fef2ea 100%)', borderBottom: '1.5px solid var(--border)', padding: '40px 0 32px' }}>
        <div className="container">
          <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 'clamp(2rem,5vw,3.2rem)', fontWeight: 400, marginBottom: '6px', color: 'var(--text-primary)' }}>
            Discover <span style={{ color: 'var(--accent)' }}>Events</span>
          </h1>
          <p style={{ color: 'var(--text-muted)', fontSize: '15px', marginBottom: '24px' }}>
            Movies, Concerts &amp; Live Events — book your seat today
          </p>
          <div style={{ position: 'relative', maxWidth: '520px' }}>
            <span style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)', fontSize: '16px', pointerEvents: 'none' }}>🔍</span>
            <input className="form-input" placeholder="Search events, movies, concerts..."
              value={search} onChange={(e) => setSearch(e.target.value)}
              style={{ paddingLeft: '44px', fontSize: '15px', borderRadius: '10px', boxShadow: 'var(--shadow)' }}
            />
          </div>
        </div>
      </div>

      <div className="container" style={{ paddingTop: '32px', paddingBottom: '40px' }}>
        <div style={{ display: 'flex', gap: '32px', alignItems: 'flex-start' }}>
          {/* Filters sidebar */}
          <div style={{ width: '210px', flexShrink: 0 }}>
            <div style={{ position: 'sticky', top: '84px' }}>
              <FilterSection title="Category">
                {TYPES.map((t) => <FilterChip key={t} label={t} active={filters.type === (t === 'ALL' ? '' : t)} onClick={() => setFilter('type', t)} />)}
              </FilterSection>
              <FilterSection title="Genre">
                {GENRES.map((g) => <FilterChip key={g} label={g} active={filters.genre === (g === 'ALL' ? '' : g)} onClick={() => setFilter('genre', g)} />)}
              </FilterSection>
              <FilterSection title="Language">
                {LANGS.map((l) => <FilterChip key={l} label={l} active={filters.language === (l === 'ALL' ? '' : l)} onClick={() => setFilter('language', l)} />)}
              </FilterSection>
              <FilterSection title="Status">
                {STATUSES.map((s) => <FilterChip key={s} label={s} active={filters.status === (s === 'ALL' ? '' : s)} onClick={() => setFilter('status', s)} />)}
              </FilterSection>
            </div>
          </div>

          {/* Results */}
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' }}>
              <span style={{ fontSize: '14px', color: 'var(--text-muted)', fontWeight: 500 }}>
                {loading ? 'Loading...' : `${events.length} result${events.length !== 1 ? 's' : ''} found`}
              </span>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.6px' }}>Sort by</span>
                <select className="form-input" value={sortBy} onChange={(e) => setSortBy(e.target.value)}
                  style={{ width: 'auto', padding: '7px 12px', fontSize: '13px' }}>
                  {SORT_OPTIONS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
                </select>
              </div>
            </div>

            {loading ? (
              <div className="loading-center"><div className="spinner" /><span>Loading events...</span></div>
            ) : events.length === 0 ? (
              <div className="empty-state">
                <div className="empty-state-icon">🎭</div>
                <h3>No Events Found</h3>
                <p style={{ fontSize: '13px' }}>Try adjusting your filters or search term</p>
              </div>
            ) : (
              <div className="grid-3 animate-fadeUp">
                {events.map((event) => <EventCard key={event.eventId} event={event} />)}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const FilterSection = ({ title, children }) => (
  <div style={{ marginBottom: '24px' }}>
    <div style={{ fontSize: '11px', fontWeight: 700, letterSpacing: '0.8px', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: '8px' }}>{title}</div>
    <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>{children}</div>
  </div>
);

const FilterChip = ({ label, active, onClick }) => (
  <button onClick={onClick} style={{ padding: '7px 12px', borderRadius: '7px', border: 'none', cursor: 'pointer', textAlign: 'left', fontSize: '13px', fontWeight: active ? 700 : 500, background: active ? 'var(--accent-dim)' : 'transparent', color: active ? 'var(--accent)' : 'var(--text-secondary)', transition: 'var(--transition)' }}
    onMouseEnter={(e) => { if (!active) e.currentTarget.style.background = 'var(--bg-secondary)'; }}
    onMouseLeave={(e) => { if (!active) e.currentTarget.style.background = 'transparent'; }}
  >{label}</button>
);

export default BrowsePage;
